    //embedded_svc.settings.fallbackRouting = []; //An array of button IDs, user IDs, or userId_buttonId
    embedded_svc.settings.offlineSupportMinimizedText = 'Contact us'; //(Defaults to Contact Us)

    embedded_svc.settings.extraPrechatFormDetails = [{
        "label": "Status",
        "value": "Open",
        "displayToAgent": true
    },{
        "label": "Origin",
        "value": "Web Chat",
        "displayToAgent": true
    },{
        "label": "Subject",
        "value": "Chat case",
        "displayToAgent": true
    }];

    embedded_svc.settings.extraPrechatInfo = [{
        "entityName": "Contact",
        "showOnCreate": true,
        "linkToEntityName": "Case",
        "linkToEntityField": "ContactId",
        "saveToTranscript": "ContactId",
        "entityFieldMaps":
            [{
                "isExactMatch": true,
                "fieldName": "FirstName",
                "doCreate": true,
                "doFind": false,
                "label": "First Name"
            }, {
                "isExactMatch": true,
                "fieldName": "LastName",
                "doCreate": true,
                "doFind": false,
                "label": "Last Name"
            }, {
                "isExactMatch": true,
                "fieldName": "Email",
                "doCreate": true,
                "doFind": true,
                "label": "Email"
            }]
